#include <iostream>
#include <stdexcept>

double divide(double a, double b) {
    if (b == 0.0) {
        throw std::invalid_argument("Divisor cannot be zero.");
    }
    return a / b;
}

int main() {
    std::cout << "Starting division test...\n";
    try {
        double result = divide(10.0, 0.0);
        std::cout << "Result: " << result << "\n";
    } catch (const std::invalid_argument& e) {
        std::cout << "Caught expected error: " << e.what() << "\n";
    }
    std::cout << "Program continued gracefully!\n";
    return 0;
}

Code Example 2 (Practical):
#include <iostream>
#include <exception>
#include <string>

class DatabaseConnectionException : public std::exception {
private:
    std::string message;
public:
    DatabaseConnectionException(const std::string& dbName) 
        : message("Failed to establish secure connection to database: " + dbName) {}

    // Override the virtual what() method with noexcept specifier
    const char* what() const noexcept override {
        return message.c_str();
    }
};

class ResourceTracker {
private:
    std::string name;
public:
    ResourceTracker(const std::string& n) : name(n) {
        std::cout << "[RAII] Resource acquired: " << name << "\n";
    }
    ~ResourceTracker() {
        std::cout << "[RAII] Resource released: " << name << "\n";
    }
};

void connectToNetwork(const std::string& server) {
    ResourceTracker tracker("NetworkSocket");
    std::cout << "Connecting to " << server << "...\n";
    throw DatabaseConnectionException(server);
}

int main() {
    std::cout << "=== Main Started ===\n";
    try {
        connectToNetwork("SecureProductionDB");
    } catch (const std::exception& e) {
        std::cout << "Main caught exception: " << e.what() << "\n";
    }
    std::cout << "=== Main Finished Safely ===\n";
    return 0;
}

